1	import { useState, useEffect, useCallback } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	
4	export interface AppNotification {
5	  id: string;
6	  type: string;
7	  title: string;
8	  body: string | null;
9	  data: Record<string, string> | null;
10	  read: boolean;
11	  created_at: string;
12	}
13	
14	const LIMIT = 40;
15	
16	export function useNotifications(userId: string) {
17	  const [notifications, setNotifications] = useState<AppNotification[]>([]);
18	  const [loading, setLoading] = useState(false);
19	
20	  const refresh = useCallback(async () => {
21	    if (!userId) return;
22	    setLoading(true);
23	    const { data } = await supabase
24	      .from("notifications")
25	      .select("id, type, title, body, data, read, created_at")
26	      .eq("user_id", userId)
27	      .order("created_at", { ascending: false })
28	      .limit(LIMIT);
29	    setNotifications((data as AppNotification[]) ?? []);
30	    setLoading(false);
31	  }, [userId]);
32	
33	  useEffect(() => {
34	    if (!userId) return;
35	    refresh();
36	
37	    const channel = supabase
38	      .channel(`notifications:${userId}`)
39	      .on(
40	        "postgres_changes",
41	        {
42	          event: "*",
43	          schema: "public",
44	          table: "notifications",
45	          filter: `user_id=eq.${userId}`,
46	        },
47	        () => refresh()
48	      )
49	      .subscribe();
50	
51	    return () => { supabase.removeChannel(channel); };
52	  }, [userId, refresh]);
53	
54	  const markRead = useCallback(async (id: string) => {
55	    await supabase.from("notifications").update({ read: true }).eq("id", id);
56	    setNotifications(prev =>
57	      prev.map(n => (n.id === id ? { ...n, read: true } : n))
58	    );
59	  }, []);
60	
61	  const markAllRead = useCallback(async () => {
62	    if (!userId) return;
63	    await supabase
64	      .from("notifications")
65	      .update({ read: true })
66	      .eq("user_id", userId)
67	      .eq("read", false);
68	    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
69	  }, [userId]);
70	
71	  const unreadCount = notifications.filter(n => !n.read).length;
72	
73	  return { notifications, unreadCount, loading, markRead, markAllRead, refresh };
74	}
